package com.enterprise.banking.service;

import javax.jws.WebService;
import javax.xml.ws.BindingType;
import javax.xml.ws.soap.SOAPBinding;
import java.math.BigDecimal;
import java.time.Instant;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@WebService(
    endpointInterface = "com.enterprise.banking.service.BankingService",
    serviceName = "BankingService",
    portName = "BankingServicePort",
    targetNamespace = "https://enterprise.bank/ws/banking"
)
@BindingType(SOAPBinding.SOAP12HTTP_BINDING)
public class BankingServiceImpl implements BankingService {

    private static final Logger LOG = LoggerFactory.getLogger(BankingServiceImpl.class);
    private final Map<String, BigDecimal> accounts = new ConcurrentHashMap<>();
    private final Map<String, String> processedTransactions = new ConcurrentHashMap<>();

    public BankingServiceImpl() {
        accounts.put("ACC-001", new BigDecimal("10000.00"));
        accounts.put("ACC-002", new BigDecimal("5000.00"));
        accounts.put("ACC-003", new BigDecimal("25000.00"));
    }

    @Override
    public TransferResponse transferFunds(TransferRequest request) {
        LOG.info("Processing transfer: {} -> {}, amount: {} {}",
            request.getSourceAccount(), request.getDestinationAccount(),
            request.getAmount(), request.getCurrency());

        TransferResponse response = new TransferResponse();
        response.setTransactionId(request.getTransactionId());
        response.setTimestamp(Instant.now().toString());

        // Idempotency check
        if (processedTransactions.containsKey(request.getTransactionId())) {
            response.setStatus("DUPLICATE");
            response.setMessage("Transaction already processed");
            return response;
        }

        // Validate
        if (request.getAmount() == null || request.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            response.setStatus("FAILED");
            response.setMessage("Invalid amount");
            return response;
        }

        BigDecimal sourceBalance = accounts.get(request.getSourceAccount());
        BigDecimal destBalance = accounts.get(request.getDestinationAccount());

        if (sourceBalance == null) {
            response.setStatus("FAILED");
            response.setMessage("Source account not found");
            return response;
        }

        if (destBalance == null) {
            response.setStatus("FAILED");
            response.setMessage("Destination account not found");
            return response;
        }

        if (sourceBalance.compareTo(request.getAmount()) < 0) {
            response.setStatus("FAILED");
            response.setMessage("Insufficient funds");
            return response;
        }

        // Process transfer
        synchronized (this) {
            accounts.put(request.getSourceAccount(), sourceBalance.subtract(request.getAmount()));
            accounts.put(request.getDestinationAccount(), destBalance.add(request.getAmount()));
        }

        processedTransactions.put(request.getTransactionId(), "COMPLETED");
        response.setStatus("SUCCESS");
        response.setMessage("Transfer completed successfully");

        LOG.info("Transfer {} completed successfully", request.getTransactionId());
        return response;
    }

    @Override
    public BalanceResponse getBalance(BalanceRequest request) {
        LOG.info("Balance inquiry for account: {}", request.getAccountNumber());

        BalanceResponse response = new BalanceResponse();
        response.setAccountNumber(request.getAccountNumber());
        response.setTimestamp(Instant.now().toString());

        BigDecimal balance = accounts.get(request.getAccountNumber());
        if (balance != null) {
            response.setBalance(balance);
            response.setCurrency("USD");
        } else {
            response.setBalance(BigDecimal.ZERO);
            response.setCurrency("USD");
        }

        return response;
    }

    @Override
    public AccountResponse createAccount(AccountRequest request) {
        LOG.info("Creating account for: {}", request.getOwnerName());

        AccountResponse response = new AccountResponse();
        response.setTimestamp(Instant.now().toString());

        String accountNumber = "ACC-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
        BigDecimal initialDeposit = request.getInitialDeposit() != null
            ? request.getInitialDeposit() : BigDecimal.ZERO;

        accounts.put(accountNumber, initialDeposit);

        response.setAccountNumber(accountNumber);
        response.setStatus("SUCCESS");
        response.setMessage("Account created successfully for " + request.getOwnerName());

        return response;
    }
}

