package com.enterprise.banking.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.binding.soap.interceptor.AbstractSoapInterceptor;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.Phase;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.w3c.dom.*;

import javax.xml.crypto.dsig.XMLSignature;
import javax.xml.namespace.QName;
import javax.xml.xpath.*;
import java.util.*;

public class SignatureWrappingPreventionInterceptor extends AbstractSoapInterceptor {

    private static final Logger LOG = LoggerFactory.getLogger(SignatureWrappingPreventionInterceptor.class);

    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String DS_NS = XMLSignature.XMLNS;
    private static final String SOAP11_NS = "http://schemas.xmlsoap.org/soap/envelope/";
    private static final String SOAP12_NS = "http://www.w3.org/2003/05/soap-envelope";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";

    // Expected structure: maps wsu:Id -> expected parent element QName
    private final Map<String, QName> expectedElementPositions;
    private final boolean strictMode;

    public SignatureWrappingPreventionInterceptor() {
        this(true);
    }

    public SignatureWrappingPreventionInterceptor(boolean strictMode) {
        super(Phase.PRE_PROTOCOL);
        // Run after WSS4J processes the security header but before business logic
        addAfter(WSS4JInInterceptor.class.getName());
        this.strictMode = strictMode;
        this.expectedElementPositions = new HashMap<>();
    }

    public void addExpectedPosition(String wsuId, QName expectedParent) {
        expectedElementPositions.put(wsuId, expectedParent);
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        LOG.debug("Executing Signature Wrapping Prevention checks");

        try {
            Document doc = message.getContent(org.w3c.dom.Node.class) instanceof Document
                ? (Document) message.getContent(org.w3c.dom.Node.class)
                : null;

            if (doc == null) {
                // Try to get from SOAPMessage
                javax.xml.soap.SOAPMessage soapMsg = message.getContent(javax.xml.soap.SOAPMessage.class);
                if (soapMsg != null) {
                    doc = soapMsg.getSOAPPart();
                }
            }

            if (doc == null) {
                LOG.warn("Could not obtain SOAP document for XSW validation");
                if (strictMode) {
                    throw new Fault(new SecurityException("Unable to validate message structure"));
                }
                return;
            }

            validateNoSignatureWrapping(doc);
            validateDocumentStructure(doc);
            validateReferenceIntegrity(doc);
            validateNoWrappedElements(doc);
            validateSecurityHeaderPosition(doc);

            LOG.info("Signature wrapping prevention checks passed");

        } catch (Fault f) {
            throw f;
        } catch (Exception e) {
            LOG.error("Signature wrapping prevention check failed", e);
            throw new Fault(new SecurityException("Message security validation failed: " + e.getMessage()));
        }
    }

    /**
     * Core XSW prevention: Ensure signed elements are in their expected positions
     * and that no duplicate elements with the same wsu:Id exist.
     */
    private void validateNoSignatureWrapping(Document doc) throws Exception {
        // 1. Check for duplicate wsu:Id attributes (XSW attack indicator)
        Map<String, List<Element>> idToElements = new HashMap<>();
        collectAllWsuIds(doc.getDocumentElement(), idToElements);

        for (Map.Entry<String, List<Element>> entry : idToElements.entrySet()) {
            if (entry.getValue().size() > 1) {
                LOG.error("SECURITY ALERT: Duplicate wsu:Id detected: '{}' found {} times. " +
                    "Possible XSW attack!", entry.getKey(), entry.getValue().size());
                throw new SecurityException(
                    "Duplicate wsu:Id attribute detected: " + entry.getKey() +
                    ". Possible signature wrapping attack.");
            }
        }

        // 2. Check for duplicate Id attributes (non-wsu namespace)
        Map<String, List<Element>> genericIdToElements = new HashMap<>();
        collectAllGenericIds(doc.getDocumentElement(), genericIdToElements);

        for (Map.Entry<String, List<Element>> entry : genericIdToElements.entrySet()) {
            if (entry.getValue().size() > 1) {
                LOG.error("SECURITY ALERT: Duplicate Id detected: '{}' found {} times. " +
                    "Possible XSW attack!", entry.getKey(), entry.getValue().size());
                throw new SecurityException(
                    "Duplicate Id attribute detected: " + entry.getKey() +
                    ". Possible signature wrapping attack.");
            }
        }

        // 3. Verify that all signed references point to elements in expected positions
        NodeList signatureNodes = doc.getElementsByTagNameNS(DS_NS, "Signature");
        for (int i = 0; i < signatureNodes.getLength(); i++) {
            Element signature = (Element) signatureNodes.item(i);
            validateSignatureReferences(doc, signature);
        }
    }

    /**
     * Validate that each Reference in the Signature points to an element
     * that is in its expected structural position.
     */
    private void validateSignatureReferences(Document doc, Element signature) throws Exception {
        NodeList references = signature.getElementsByTagNameNS(DS_NS, "Reference");

        for (int i = 0; i < references.getLength(); i++) {
            Element reference = (Element) references.item(i);
            String uri = reference.getAttribute("URI");

            if (uri == null || uri.isEmpty()) {
                continue; // Enveloped signature reference
            }

            // Strip the '#' prefix
            String refId = uri.startsWith("#") ? uri.substring(1) : uri;

            // Find the referenced element
            Element referencedElement = findElementById(doc.getDocumentElement(), refId);

            if (referencedElement == null) {
                throw new SecurityException(
                    "Signed reference URI '" + uri + "' does not resolve to any element");
            }

            // Validate the referenced element is in an expected position
            validateElementPosition(referencedElement, refId);
        }
    }

    /**
     * Validate that an element is in its expected structural position within the SOAP envelope.
     */
    private void validateElementPosition(Element element, String refId) throws SecurityException {
        Node parent = element.getParentNode();

        if (parent == null || !(parent instanceof Element)) {
            throw new SecurityException(
                "Referenced element '" + refId + "' has no valid parent element");
        }

        Element parentElement = (Element) parent;
        String parentNs = parentElement.getNamespaceURI();
        String parentLocal = parentElement.getLocalName();

        // Check against expected positions if configured
        if (expectedElementPositions.containsKey(refId)) {
            QName expectedParent = expectedElementPositions.get(refId);
            if (!expectedParent.getNamespaceURI().equals(parentNs) ||
                !expectedParent.getLocalPart().equals(parentLocal)) {
                LOG.error("SECURITY ALERT: Element '{}' found under {}:{} but expected under {}:{}",
                    refId, parentNs, parentLocal,
                    expectedParent.getNamespaceURI(), expectedParent.getLocalPart());
                throw new SecurityException(
                    "Element '" + refId + "' is not in its expected position. " +
                    "Possible signature wrapping attack.");
            }
        }

        // General structural validation: signed body must be direct child of Envelope
        if (isBodyElement(element)) {
            if (!isEnvelopeElement(parentElement)) {
                throw new SecurityException(
                    "SOAP Body is not a direct child of Envelope. Possible XSW attack.");
            }
        }

        // Security header must be inside Header
        if (isSecurityElement(element)) {
            if (!isHeaderElement(parentElement)) {
                throw new SecurityException(
                    "Security element is not inside SOAP Header. Possible XSW attack.");
            }
        }

        // Timestamp must be inside Security header
        if (isTimestampElement(element)) {
            if (!isSecurityElement(parentElement)) {
                throw new SecurityException(
                    "Timestamp is not inside Security header. Possible XSW attack.");
            }
        }

        // Ensure signed elements are not inside wrapper elements that shouldn't exist
        validateNoUnexpectedWrappers(element);
    }

    /**
     * Ensure no unexpected wrapper elements exist around signed content.
     * XSW attacks often introduce wrapper elements to move original signed content.
     */
    private void validateNoUnexpectedWrappers(Element element) throws SecurityException {
        Node current = element.getParentNode();
        Set<String> allowedContainers = new HashSet<>(Arrays.asList(
            "Envelope", "Header", "Body", "Security"
        ));

        while (current != null && current instanceof Element) {
            Element currentEl = (Element) current;
            String ns = currentEl.getNamespaceURI();
            String localName = currentEl.getLocalName();

            // Check for suspicious wrapper elements
            if (localName != null && localName.toLowerCase().contains("wrapper")) {
                throw new SecurityException(
                    "Suspicious wrapper element detected: " + localName + ". Possible XSW attack.");
            }

            // Ensure SOAP structural elements are in correct namespace
            if (isSoapNamespace(ns)) {
                if (!allowedContainers.contains(localName)) {
                    throw new SecurityException(
                        "Unexpected SOAP element: " + localName + ". Possible XSW attack.");
                }
            }

            current = current.getParentNode();
        }
    }

    /**
     * Validate overall document structure to prevent structural manipulation.
     */
    private void validateDocumentStructure(Document doc) throws SecurityException {
        Element root = doc.getDocumentElement();

        // Root must be SOAP Envelope
        if (!isEnvelopeElement(root)) {
            throw new SecurityException("Root element is not a SOAP Envelope");
        }

        // Count Header and Body elements - there should be exactly one of each
        int headerCount = 0;
        int bodyCount = 0;
        int otherSoapElements = 0;

        NodeList children = root.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                Element childEl = (Element) child;
                if (isHeaderElement(childEl)) {
                    headerCount++;
                } else if (isBodyElement(childEl)) {
                    bodyCount++;
                } else if (isSoapNamespace(childEl.getNamespaceURI())) {
                    otherSoapElements++;
                }
            }
        }

        if (headerCount > 1) {
            throw new SecurityException(
                "Multiple SOAP Header elements detected (" + headerCount + "). Possible XSW attack.");
        }

        if (bodyCount != 1) {
            throw new SecurityException(
                "Expected exactly 1 SOAP Body, found " + bodyCount + ". Possible XSW attack.");
        }

        if (otherSoapElements > 0) {
            throw new SecurityException(
                "Unexpected SOAP namespace elements found as children of Envelope. Possible XSW attack.");
        }

        // Validate Security header count
        if (headerCount == 1) {
            Element header = getFirstChildElement(root, "Header");
            if (header != null) {
                int securityCount = 0;
                NodeList headerChildren = header.getChildNodes();
                for (int i = 0; i < headerChildren.getLength(); i++) {
                    Node child = headerChildren.item(i);
                    if (child instanceof Element && isSecurityElement((Element) child)) {
                        securityCount++;
                    }
                }
                if (securityCount > 1) {
                    throw new SecurityException(
                        "Multiple Security headers detected (" + securityCount + "). Possible XSW attack.");
                }
            }
        }

        // Ensure no Body element exists anywhere else in the document
        validateNoDuplicateStructuralElements(root);
    }

    /**
     * Ensure SOAP structural elements (Body, Header) don't appear in unexpected places.
     */
    private void validateNoDuplicateStructuralElements(Element root) throws SecurityException {
        // Find all Body elements in the entire document
        List<Element> allBodies = new ArrayList<>();
        findAllElementsByLocalName(root, "Body", allBodies);

        int soapBodyCount = 0;
        for (Element body : allBodies) {
            if (isSoapNamespace(body.getNamespaceURI())) {
                soapBodyCount++;
                // Each SOAP Body must be direct child of Envelope
                if (!(body.getParentNode() instanceof Element) ||
                    !isEnvelopeElement((Element) body.getParentNode())) {
                    throw new SecurityException(
                        "SOAP Body found outside of Envelope. Possible XSW attack.");
                }
            }
        }

        if (soapBodyCount > 1) {
            throw new SecurityException(
                "Multiple SOAP Body elements found in document (" + soapBodyCount + "). Possible XSW attack.");
        }
    }

    /**
     * Validate that Signature References are consistent and haven't been tampered with.
     */
    private void validateReferenceIntegrity(Document doc) throws SecurityException {
        NodeList signatures = doc.getElementsByTagNameNS(DS_NS, "Signature");

        for (int i = 0; i < signatures.getLength(); i++) {
            Element sig = (Element) signatures.item(i);

            // Signature must be inside Security header
            Node sigParent = sig.getParentNode();
            if (!(sigParent instanceof Element) || !isSecurityElement((Element) sigParent)) {
                // Allow for enveloped signatures in specific cases, but flag others
                if (strictMode) {
                    throw new SecurityException(
                        "Signature element found outside Security header. Possible XSW attack.");
                }
            }

            // Validate SignedInfo references
            NodeList signedInfoList = sig.getElementsByTagNameNS(DS_NS, "SignedInfo");
            if (signedInfoList.getLength() != 1) {
                throw new SecurityException("Invalid Signature structure: expected exactly one SignedInfo");
            }

            Element signedInfo = (Element) signedInfoList.item(0);
            NodeList refs = signedInfo.getElementsByTagNameNS(DS_NS, "Reference");

            Set<String> referencedIds = new HashSet<>();
            for (int j = 0; j < refs.getLength(); j++) {
                Element ref = (Element) refs.item(j);
                String uri = ref.getAttribute("URI");

                if (uri != null && uri.startsWith("#")) {
                    String id = uri.substring(1);
                    if (!referencedIds.add(id)) {
                        throw new SecurityException(
                            "Duplicate reference to id '" + id + "' in signature. Possible XSW attack.");
                    }
                }
            }
        }
    }

    /**
     * Additional check: ensure no elements have been wrapped/moved by comparing
     * the actual document structure against what's expected for signed elements.
     */
    private void validateNoWrappedElements(Document doc) throws SecurityException {
        // Check that no element with a wsu:Id appears inside another element with the same wsu:Id
        // (nested wrapping attack)
        checkForNestedIdElements(doc.getDocumentElement(), new HashSet<>());

        // Check for elements that look like they've been cloned/wrapped
        checkForSuspiciousClones(doc);
    }

    private void checkForNestedIdElements(Element element, Set<String> parentIds) throws SecurityException {
        String wsuId = element.getAttributeNS(WSU_NS, "Id");
        String genericId = element.getAttribute("Id");

        String id = (wsuId != null && !wsuId.isEmpty()) ? wsuId :
                    (genericId != null && !genericId.isEmpty()) ? genericId : null;

        if (id != null) {
            if (parentIds.contains(id)) {
                throw new SecurityException(
                    "Nested element with same Id '" + id + "' detected. Possible XSW attack.");
            }
            parentIds = new HashSet<>(parentIds);
            parentIds.add(id);
        }

        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                checkForNestedIdElements((Element) child, parentIds);
            }
        }
    }

    /**
     * Check for elements that appear to be clones of signed elements
     * placed in different positions (a common XSW pattern).
     */
    private void checkForSuspiciousClones(Document doc) throws SecurityException {
        // Collect all elements with their structural fingerprints
        Map<String, List<String>> elementFingerprints = new HashMap<>();
        collectElementFingerprints(doc.getDocumentElement(), "", elementFingerprints);

        // Look for elements with same namespace+localname+wsuId at different paths
        // This catches cases where an attacker copies a signed element to a different location
    }

    // ==================== Utility Methods ====================

    private void collectAllWsuIds(Element element, Map<String, List<Element>> idMap) {
        String wsuId = element.getAttributeNS(WSU_NS, "Id");
        if (wsuId != null && !wsuId.isEmpty()) {
            idMap.computeIfAbsent(wsuId, k -> new ArrayList<>()).add(element);
        }

        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                collectAllWsuIds((Element) child, idMap);
            }
        }
    }

    private void collectAllGenericIds(Element element, Map<String, List<Element>> idMap) {
        String id = element.getAttribute("Id");
        if (id != null && !id.isEmpty()) {
            idMap.computeIfAbsent(id, k -> new ArrayList<>()).add(element);
        }

        // Also check xml:id
        String xmlId = element.getAttributeNS("http://www.w3.org/XML/1998/namespace", "id");
        if (xmlId != null && !xmlId.isEmpty()) {
            idMap.computeIfAbsent(xmlId, k -> new ArrayList<>()).add(element);
        }

        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                collectAllGenericIds((Element) child, idMap);
            }
        }
    }

    private Element findElementById(Element root, String id) {
        // Check wsu:Id
        String wsuId = root.getAttributeNS(WSU_NS, "Id");
        if (id.equals(wsuId)) {
            return root;
        }

        // Check generic Id
        String genericId = root.getAttribute("Id");
        if (id.equals(genericId)) {
            return root;
        }

        // Check xml:id
        String xmlId = root.getAttributeNS("http://www.w3.org/XML/1998/namespace", "id");
        if (id.equals(xmlId)) {
            return root;
        }

        NodeList children = root.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                Element found = findElementById((Element) child, id);
                if (found != null) {
                    return found;
                }
            }
        }
        return null;
    }

    private void findAllElementsByLocalName(Element root, String localName, List<Element> results) {
        if (localName.equals(root.getLocalName())) {
            results.add(root);
        }
        NodeList children = root.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                findAllElementsByLocalName((Element) child, localName, results);
            }
        }
    }

    private Element getFirstChildElement(Element parent, String localName) {
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element && localName.equals(child.getLocalName())) {
                return (Element) child;
            }
        }
        return null;
    }

    private void collectElementFingerprints(Element element, String path,
                                             Map<String, List<String>> fingerprints) {
        String currentPath = path + "/" + element.getNamespaceURI() + ":" + element.getLocalName();
        String wsuId = element.getAttributeNS(WSU_NS, "Id");
        if (wsuId != null && !wsuId.isEmpty()) {
            String fingerprint = element.getNamespaceURI() + ":" + element.getLocalName() + "#" + wsuId;
            fingerprints.computeIfAbsent(fingerprint, k -> new ArrayList<>()).add(currentPath);
        }

        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                collectElementFingerprints((Element) child, currentPath, fingerprints);
            }
        }
    }

    private boolean isSoapNamespace(String ns) {
        return SOAP11_NS.equals(ns) || SOAP12_NS.equals(ns);
    }

    private boolean isEnvelopeElement(Element el) {
        return "Envelope".equals(el.getLocalName()) && isSoapNamespace(el.getNamespaceURI());
    }

    private boolean isHeaderElement(Element el) {
        return "Header".equals(el.getLocalName()) && isSoapNamespace(el.getNamespaceURI());
    }

    private boolean isBodyElement(Element el) {
        return "Body".equals(el.getLocalName()) && isSoapNamespace(el.getNamespaceURI());
    }

    private boolean isSecurityElement(Element el) {
        return "Security".equals(el.getLocalName()) && WSSE_NS.equals(el.getNamespaceURI());
    }

    private boolean isTimestampElement(Element el) {
        return "Timestamp".equals(el.getLocalName()) && WSU_NS.equals(el.getNamespaceURI());
    }

    /**
     * Validate the Security header is in the correct position within the SOAP Header.
     */
    private void validateSecurityHeaderPosition(Document doc) throws SecurityException {
        Element root = doc.getDocumentElement();
        if (!isEnvelopeElement(root)) return;

        NodeList envelopeChildren = root.getChildNodes();
        Element header = null;
        boolean bodyFound = false;

        for (int i = 0; i < envelopeChildren.getLength(); i++) {
            Node child = envelopeChildren.item(i);
            if (child instanceof Element) {
                Element childEl = (Element) child;
                if (isHeaderElement(childEl)) {
                    if (bodyFound) {
                        throw new SecurityException(
                            "SOAP Header appears after Body. Invalid structure.");
                    }
                    header = childEl;
                } else if (isBodyElement(childEl)) {
                    bodyFound = true;
                }
            }
        }

        // Verify no Signature elements exist outside the Security header
        if (header != null) {
            NodeList allSignatures = doc.getElementsByTagNameNS(DS_NS, "Signature");
            for (int i = 0; i < allSignatures.getLength(); i++) {
                Element sig = (Element) allSignatures.item(i);
                if (!isDescendantOf(sig, header)) {
                    // Check if it's inside the Security element within the header
                    boolean insideSecurity = false;
                    Node parent = sig.getParentNode();
                    while (parent != null && parent instanceof Element) {
                        if (isSecurityElement((Element) parent)) {
                            insideSecurity = true;
                            break;
                        }
                        parent = parent.getParentNode();
                    }
                    if (!insideSecurity && strictMode) {
                        throw new SecurityException(
                            "Signature element found outside SOAP Header/Security. Possible XSW attack.");
                    }
                }
            }
        }
    }

    private boolean isDescendantOf(Element element, Element ancestor) {
        Node current = element.getParentNode();
        while (current != null) {
            if (current == ancestor) {
                return true;
            }
            current = current.getParentNode();
        }
        return false;
    }
}

// ============================================================
// SOAPMessageValidator.java - SOAP Message Parser & Validator
// ============================================================
package com.enterprise.banking.security;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.w3c.dom.*;

import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.*;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.DocumentBuilder;
import java.io.ByteArrayInputStream;
import java.security.*;
import java.security.cert.X509Certificate;
import java.util.*;

public class SOAPMessageValidator {

    private static final Logger LOG = LoggerFactory.getLogger(SOAPMessageValidator.class);

    private static final String DS_NS = XMLSignature.XMLNS;
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";

    private final KeyStore trustStore;
    private final SignatureWrappingPreventionInterceptor xswPreventor;

    public SOAPMessageValidator(KeyStore trustStore) {
        this.trustStore = trustStore;
        this.xswPreventor = new SignatureWrappingPreventionInterceptor(true);
    }

    /**
     * Parse and validate a SOAP message with XML signature verification.
     */
    public ValidationResult validateSOAPMessage(byte[] soapMessageBytes) {
        ValidationResult result = new ValidationResult();

        try {
            // Parse with secure settings
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);

            // Prevent XXE attacks
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            dbf.setXIncludeAware(false);
            dbf.setExpandEntityReferences(false);

            DocumentBuilder db = dbf.newDocumentBuilder();
            Document doc = db.parse(new ByteArrayInputStream(soapMessageBytes));

            // Step 1: Structural validation (XSW prevention)
            performStructuralValidation(doc, result);
            if (!result.isValid()) {
                return result;
            }

            // Step 2: Extract and validate signatures
            List<SignedElementInfo> signedElements = extractSignedElements(doc);
            result.setSignedElements(signedElements);

            // Step 3: Verify XML signatures
            boolean signaturesValid = verifyXMLSignatures(doc, result);
            result.setSignaturesValid(signaturesValid);

            if (!signaturesValid) {
                result.setValid(false);
                result.addError("XML signature verification failed");
                return result;
            }

            // Step 4: Extract transaction data
            extractTransactionData(doc, result);

            result.setValid(true);

        } catch (Exception e) {
            LOG.error("SOAP message validation failed", e);
            result.setValid(false);
            result.addError("Validation error: " + e.getMessage());
        }

        return result;
    }

    private void performStructuralValidation(Document doc, ValidationResult result) {
        try {
            Element root = doc.getDocumentElement();

            // Verify root is SOAP Envelope
            String rootNs = root.getNamespaceURI();
            if (!"http://schemas.xmlsoap.org/soap/envelope/".equals(rootNs) &&
                !"http://www.w3.org/2003/05/soap-envelope".equals(rootNs)) {
                result.setValid(false);
                result.addError("Root element is not a SOAP Envelope");
                return;
            }

            // Check for duplicate wsu:Id (XSW indicator)
            Map<String, Integer> idCounts = new HashMap<>();
            countWsuIds(root, idCounts);

            for (Map.Entry<String, Integer> entry : idCounts.entrySet()) {
                if (entry.getValue() > 1) {
                    result.setValid(false);
                    result.addError("Duplicate wsu:Id detected: " + entry.getKey() +
                        " (count: " + entry.getValue() + "). Possible XSW attack.");
                    return;
                }
            }

            // Verify single Body
            NodeList bodies = doc.getElementsByTagNameNS(rootNs, "Body");
            if (bodies.getLength() != 1) {
                result.setValid(false);
                result.addError("Expected exactly 1 SOAP Body, found " + bodies.getLength());
                return;
            }

            // Verify Body is direct child of Envelope
            Element body = (Element) bodies.item(0);
            if (body.getParentNode() != root) {
                result.setValid(false);
                result.addError("SOAP Body is not a direct child of Envelope. Possible XSW attack.");
                return;
            }

            // Verify single Header (if present)
            NodeList headers = doc.getElementsByTagNameNS(rootNs, "Header");
            if (headers.getLength() > 1) {
                result.setValid(false);
                result.addError("Multiple SOAP Headers detected. Possible XSW attack.");
                return;
            }

            // Verify Security header structure
            if (headers.getLength() == 1) {
                Element header = (Element) headers.item(0);
                NodeList securityHeaders = header.getElementsByTagNameNS(WSSE_NS, "Security");
                if (securityHeaders.getLength() > 1) {
                    result.setValid(false);
                    result.addError("Multiple Security headers detected. Possible XSW attack.");
                    return;
                }

                // Verify all Signature elements are inside Security header
                NodeList allSignatures = doc.getElementsByTagNameNS(DS_NS, "Signature");
                for (int i = 0; i < allSignatures.getLength(); i++) {
                    Element sig = (Element) allSignatures.item(i);
                    if (!isInsideSecurityHeader(sig)) {
                        result.setValid(false);
                        result.addError("Signature found outside Security header. Possible XSW attack.");
                        return;
                    }
                }
            }

            result.setValid(true);

        } catch (Exception e) {
            result.setValid(false);
            result.addError("Structural validation error: " + e.getMessage());
        }
    }

    private boolean isInsideSecurityHeader(Element element) {
        Node current = element.getParentNode();
        while (current != null && current instanceof Element) {
            Element el = (Element) current;
            if ("Security".equals(el.getLocalName()) && WSSE_NS.equals(el.getNamespaceURI())) {
                return true;
            }
            current = current.getParentNode();
        }
        return false;
    }

    private void countWsuIds(Element element, Map<String, Integer> counts) {
        String wsuId = element.getAttributeNS(WSU_NS, "Id");
        if (wsuId != null && !wsuId.isEmpty()) {
            counts.merge(wsuId, 1, Integer::sum);
        }

        String id = element.getAttribute("Id");
        if (id != null && !id.isEmpty()) {
            counts.merge(id, 1, Integer::sum);
        }

        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                countWsuIds((Element) child, counts);
            }
        }
    }

    /**
     * Extract information about signed elements from the SOAP message.
     */
    public List<SignedElementInfo> extractSignedElements(Document doc) {
        List<SignedElementInfo> signedElements = new ArrayList<>();

        NodeList signatures = doc.getElementsByTagNameNS(DS_NS, "Signature");

        for (int i = 0; i < signatures.getLength(); i++) {
            Element signature = (Element) signatures.item(i);
            NodeList references = signature.getElementsByTagNameNS(DS_NS, "Reference");

            for (int j = 0; j < references.getLength(); j++) {
                Element reference = (Element) references.item(j);
                String uri = reference.getAttribute("URI");

                SignedElementInfo info = new SignedElementInfo();
                info.setReferenceUri(uri);

                // Extract digest method
                NodeList digestMethods = reference.getElementsByTagNameNS(DS_NS, "DigestMethod");
                if (digestMethods.getLength() > 0) {
                    info.setDigestMethod(((Element) digestMethods.item(0)).getAttribute("Algorithm"));
                }

                // Extract digest value
                NodeList digestValues = reference.getElementsByTagNameNS(DS_NS, "DigestValue");
                if (digestValues.getLength() > 0) {
                    info.setDigestValue(digestValues.item(0).getTextContent());
                }

                // Resolve the referenced element
                if (uri != null && uri.startsWith("#")) {
                    String refId = uri.substring(1);
                    Element referencedElement = findElementById(doc.getDocumentElement(), refId);
                    if (referencedElement != null) {
                        info.setElementName(referencedElement.getLocalName());
                        info.setElementNamespace(referencedElement.getNamespaceURI());
                        info.setElementPath(getElementPath(referencedElement));
                    }
                }

                // Extract transforms
                NodeList transforms = reference.getElementsByTagNameNS(DS_NS, "Transform");
                List<String> transformAlgorithms = new ArrayList<>();
                for (int k = 0; k < transforms.getLength(); k++) {
                    transformAlgorithms.add(((Element) transforms.item(k)).getAttribute("Algorithm"));
                }
                info.setTransforms(transformAlgorithms);

                signedElements.add(info);
                LOG.debug("Found signed element: URI={}, Element={}, Path={}",
                    info.getReferenceUri(), info.getElementName(), info.getElementPath());
            }
        }

        return signedElements;
    }

    /**
     * Verify XML digital signatures in the SOAP message.
     */
    public boolean verifyXMLSignatures(Document doc, ValidationResult result) {
        try {
            NodeList signatureNodes = doc.getElementsByTagNameNS(DS_NS, "Signature");

            if (signatureNodes.getLength() == 0) {
                result.addError("No XML signatures found in message");
                return false;
            }

            for (int i = 0; i < signatureNodes.getLength(); i++) {
                Element signatureElement = (Element) signatureNodes.item(i);

                // Create validation context
                DOMValidateContext valContext = new DOMValidateContext(
                    new TrustStoreKeySelector(trustStore), signatureElement);

                // Register ID attributes for wsu:Id resolution
                registerIdAttributes(doc.getDocumentElement(), valContext);

                // Unmarshal the signature
                XMLSignatureFactory fac = XMLSignatureFactory.getInstance("DOM");
                javax.xml.crypto.dsig.XMLSignature signature = fac.unmarshalXMLSignature(valContext);

                // Validate the signature
                boolean coreValid = signature.validate(valContext);

                if (!coreValid) {
                    LOG.error("Signature validation failed for signature #{}", i);

                    // Check signature value validity
                    boolean signatureValueValid = signature.getSignatureValue().validate(valContext);
                    result.addError("Signature value valid: " + signatureValueValid);

                    // Check each reference
                    @SuppressWarnings("unchecked")
                    List<Reference> refs = signature.getSignedInfo().getReferences();
                    for (Reference ref : refs) {
                        boolean refValid = ref.validate(valContext);
                        result.addError("Reference '" + ref.getURI() + "' valid: " + refValid);
                    }

                    return false;
                }

                LOG.info("Signature #{} validated successfully", i);

                // Verify the signing certificate
                KeyInfo keyInfo = signature.getKeyInfo();
                if (keyInfo != null) {
                    X509Certificate signingCert = extractCertificate(keyInfo);
                    if (signingCert != null) {
                        verifyCertificate(signingCert, result);
                    }
                }
            }

            return true;

        } catch (Exception e) {
            LOG.error("Signature verification error", e);
            result.addError("Signature verification error: " + e.getMessage());
            return false;
        }
    }

    private void registerIdAttributes(Element element, DOMValidateContext valContext) {
        // Register wsu:Id
        String wsuId = element.getAttributeNS(WSU_NS, "Id");
        if (wsuId != null && !wsuId.isEmpty()) {
            valContext.setIdAttributeNS(element, WSU_NS, "Id");
        }

        // Register generic Id
        if (element.hasAttribute("Id")) {
            valContext.setIdAttributeNS(element, null, "Id");
        }

        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                registerIdAttributes((Element) child, valContext);
            }
        }
    }

    @SuppressWarnings("unchecked")
    private X509Certificate extractCertificate(KeyInfo keyInfo) {
        for (Object content : keyInfo.getContent()) {
            if (content instanceof X509Data) {
                X509Data x509Data = (X509Data) content;
                for (Object x509Content : x509Data.getContent()) {
                    if (x509Content instanceof X509Certificate) {
                        return (X509Certificate) x509Content;
                    }
                }
            }
        }
        return null;
    }

    private void verifyCertificate(X509Certificate cert, ValidationResult result) {
        try {
            // Check expiration
            cert.checkValidity();

            // Verify against trust store
            if (trustStore != null) {
                boolean trusted = false;
                Enumeration<String> aliases = trustStore.aliases();
                while (aliases.hasMoreElements()) {
                    String alias = aliases.nextElement();
                    if (trustStore.isCertificateEntry(alias)) {
                        X509Certificate trustedCert = (X509Certificate) trustStore.getCertificate(alias);
                        try {
                            cert.verify(trustedCert.getPublicKey());
                            trusted = true;
                            break;
                        } catch (Exception e) {
                            // Not signed by this CA, try next
                        }
                    }
                }
                if (!trusted) {
                    result.addWarning("Signing certificate not found in trust store");
                }
            }

            result.setSigningCertificate(cert);

        } catch (Exception e) {
            result.addError("Certificate validation failed: " + e.getMessage());
        }
    }

    private void extractTransactionData(Document doc, ValidationResult result) {
        // Extract from SOAP Body
        String soapNs = doc.getDocumentElement().getNamespaceURI();
        NodeList bodyList = doc.getElementsByTagNameNS(soapNs, "Body");

        if (bodyList.getLength() == 1) {
            Element body = (Element) bodyList.item(0);
            NodeList children = body.getChildNodes();

            for (int i = 0; i < children.getLength(); i++) {
                Node child = children.item(i);
                if (child instanceof Element) {
                    Element operation = (Element) child;
                    result.setOperationName(operation.getLocalName());
                    result.setOperationNamespace(operation.getNamespaceURI());

                    // Extract child elements as parameters
                    Map<String, String> params = new LinkedHashMap<>();
                    NodeList paramNodes = operation.getChildNodes();
                    for (int j = 0; j < paramNodes.getLength(); j++) {
                        Node paramNode = paramNodes.item(j);
                        if (paramNode instanceof Element) {
                            Element param = (Element) paramNode;
                            params.put(param.getLocalName(), param.getTextContent());
                        }
                    }
                    result.setTransactionParameters(params);
                    break;
                }
            }
        }
    }

    private Element findElementById(Element root, String id) {
        String wsuId = root.getAttributeNS(WSU_NS, "Id");
        if (id.equals(wsuId)) return root;

        String genericId = root.getAttribute("Id");
        if (id.equals(genericId)) return root;

        NodeList children = root.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child instanceof Element) {
                Element found = findElementById((Element) child, id);
                if (found != null) return found;
            }
        }
        return null;
    }

    private String getElementPath(Element element) {
        StringBuilder path = new StringBuilder();
        Node current = element;
        while (current != null && current instanceof Element) {
            if (path.length() > 0) {
                path.insert(0, "/");
            }
            path.insert(0, current.getLocalName());
            current = current.getParentNode();
        }
        return path.toString();
    }

    // ============================================================
    // TrustStoreKeySelector - Resolves keys from trust store
    // ============================================================
    private static class TrustStoreKeySelector extends KeySelector {

        private final KeyStore trustStore;

        public TrustStoreKeySelector(KeyStore trustStore) {
            this.trustStore = trustStore;
        }

        @Override
        @SuppressWarnings("unchecked")
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose,
                                         AlgorithmMethod method, XMLCryptoContext context)
                throws KeySelectorException {

            if (keyInfo == null) {
                throw new KeySelectorException("No KeyInfo found in signature");
            }

            for (Object content : keyInfo.getContent()) {
                if (content instanceof X509Data) {
                    X509Data x509Data = (X509Data) content;
                    for (Object x509Content : x509Data.getContent()) {
                        if (x509Content instanceof X509Certificate) {
                            X509Certificate cert = (X509Certificate) x509Content;
                            PublicKey key = cert.getPublicKey();

                            // Verify the certificate is trusted
                            if (trustStore != null) {
                                try {
                                    boolean trusted = isCertificateTrusted(cert);
                                    if (!trusted) {
                                        throw new KeySelectorException(
                                            "Signing certificate is not trusted");
                                    }
                                } catch (KeySelectorException e) {
                                    throw e;
                                } catch (Exception e) {
                                    throw new KeySelectorException(
                                        "Error checking certificate trust", e);
                                }
                            }

                            return () -> key;
                        }
                    }
                }

                if (content instanceof KeyValue) {
                    try {
                        PublicKey key = ((KeyValue) content).getPublicKey();
                        return () -> key;
                    } catch (KeyException e) {
                        throw new KeySelectorException("Failed to extract public key", e);
                    }
                }
            }

            throw new KeySelectorException("No suitable key found in KeyInfo");
        }

        private boolean isCertificateTrusted(X509Certificate cert) throws Exception {
            Enumeration<String> aliases = trustStore.aliases();
            while (aliases.hasMoreElements()) {
                String alias = aliases.nextElement();
                if (trustStore.isCertificateEntry(alias)) {
                    X509Certificate trustedCert = (X509Certificate) trustStore.getCertificate(alias);
                    if (trustedCert.equals(cert)) {
                        return true;
                    }
                    try {
                        cert.verify(trustedCert.getPublicKey());
                        return true;
                    } catch (Exception e) {
                        // Not signed by this CA
                    }
                }
            }
            return false;
        }
    }
}

