package com.enterprise.banking.security;

import java.util.List;

public class SignedElementInfo {
    private String referenceUri;
    private String elementName;
    private String elementNamespace;
    private String elementPath;
    private String digestMethod;
    private String digestValue;
    private List<String> transforms;

    public String getReferenceUri() { return referenceUri; }
    public void setReferenceUri(String referenceUri) { this.referenceUri = referenceUri; }
    public String getElementName() { return elementName; }
    public void setElementName(String elementName) { this.elementName = elementName; }
    public String getElementNamespace() { return elementNamespace; }
    public void setElementNamespace(String elementNamespace) { this.elementNamespace = elementNamespace; }
    public String getElementPath() { return elementPath; }
    public void setElementPath(String elementPath) { this.elementPath = elementPath; }
    public String getDigestMethod() { return digestMethod; }
    public void setDigestMethod(String digestMethod) { this.digestMethod = digestMethod; }
    public String getDigestValue() { return digestValue; }
    public void setDigestValue(String digestValue) { this.digestValue = digestValue; }
    public List<String> getTransforms() { return transforms; }
    public void setTransforms(List<String> transforms) { this.transforms = transforms; }

    @Override
    public String toString() {
        return "SignedElementInfo{uri='" + referenceUri + "', element='" + elementName +
            "', path='" + elementPath + "', digest='" + digestMethod + "'}";
    }
}

